mapper.select:
SELECT t.pause_id AS pauseId, t.user_id AS userId, u.nickname AS nickname, u.phone AS phone, t.card_order_id AS cardOrderId, fc.cardName AS cardName, DATE_FORMAT(t.start_time, '%Y-%m-%d %H:%i:%s') AS startTime, DATE_FORMAT(t.end_time, '%Y-%m-%d %H:%i:%s') AS endTime, t.pause_days AS pauseDays, t.status AS status, DATE_FORMAT(t.created_date, '%Y-%m-%d %H:%i:%s') AS createdDate, (SELECT COUNT(1) FROM card_pause_record p2 WHERE p2.card_order_id = t.card_order_id AND YEAR(p2.created_date) = YEAR(t.created_date)) AS yearCount FROM card_pause_record t LEFT JOIN user_info u ON t.user_id = u.userId LEFT JOIN card_order co ON t.card_order_id = co.cardOrderId LEFT JOIN fit_card fc ON co.cardId = fc.fitCardId
ORDER BY t.created_date DESC
LIMIT #{offset}, #{limit}
